import{_ as n,o as a,c as e,ai as p}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"OpenProse","description":"","frontmatter":{"read_when":["你想运行或编写 .prose 工作流","你想启用 OpenProse 插件","你需要了解状态存储"],"summary":"OpenProse：OpenSoul 中的 .prose 工作流、斜杠命令和状态","title":"OpenProse","x-i18n":{"generated_at":"2026-02-03T07:53:38Z","model":"claude-opus-4-5","provider":"pi","source_hash":"cf7301e927b9a46347b498e264aeaa10dd76e85ff2de04775be57435718339f5","source_path":"prose.md","workflow":15}},"headers":[],"relativePath":"zh-CN/prose.md","filePath":"zh-CN/prose.md","lastUpdated":1771906665000}'),l={name:"zh-CN/prose.md"};function r(i,s,o,t,c,d){return a(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="openprose" tabindex="-1"><a class="header-anchor" href="#openprose">#</a> OpenProse</h1><p>OpenProse 是一种可移植的、以 Markdown 为中心的工作流格式，用于编排 AI 会话。在 OpenSoul 中，它作为插件发布，安装一个 OpenProse Skills 包以及一个 <code>/prose</code> 斜杠命令。程序存放在 <code>.prose</code> 文件中，可以生成多个具有显式控制流的子智能体。</p><p>官方网站：<a href="https://www.prose.md" target="_blank" rel="noreferrer">https://www.prose.md</a></p><h2 id="它能做什么" tabindex="-1"><a class="header-anchor" href="#它能做什么">#</a> 它能做什么</h2><ul><li>具有显式并行性的多智能体研究 + 综合。</li><li>可重复的批准安全工作流（代码审查、事件分类、内容管道）。</li><li>可在支持的智能体运行时之间运行的可重用 <code>.prose</code> 程序。</li></ul><h2 id="安装-启用" tabindex="-1"><a class="header-anchor" href="#安装-启用">#</a> 安装 + 启用</h2><p>捆绑的插件默认是禁用的。启用 OpenProse：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open-prose</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>启用插件后重启 Gateway 网关。</p><p>开发/本地检出：<code>opensoul plugins install ./extensions/open-prose</code></p><p>相关文档：<a href="/docs/tools/plugin">插件</a>、<a href="/docs/plugins/manifest">插件清单</a>、<a href="/docs/tools/skills">Skills</a>。</p><h2 id="斜杠命令" tabindex="-1"><a class="header-anchor" href="#斜杠命令">#</a> 斜杠命令</h2><p>OpenProse 将 <code>/prose</code> 注册为用户可调用的 Skills 命令。它路由到 OpenProse VM 指令，并在底层使用 OpenSoul 工具。</p><p>常用命令：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/prose help</span></span>
<span class="line"><span>/prose run &lt;file.prose&gt;</span></span>
<span class="line"><span>/prose run &lt;handle/slug&gt;</span></span>
<span class="line"><span>/prose run &lt;https://example.com/file.prose&gt;</span></span>
<span class="line"><span>/prose compile &lt;file.prose&gt;</span></span>
<span class="line"><span>/prose examples</span></span>
<span class="line"><span>/prose update</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="示例-一个简单的-prose-文件" tabindex="-1"><a class="header-anchor" href="#示例-一个简单的-prose-文件">#</a> 示例：一个简单的 <code>.prose</code> 文件</h2><div class="language-prose vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">prose</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Research + synthesis with two agents running in parallel.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>input topic: &quot;What should we research?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>agent researcher:</span></span>
<span class="line"><span>  model: sonnet</span></span>
<span class="line"><span>  prompt: &quot;You research thoroughly and cite sources.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>agent writer:</span></span>
<span class="line"><span>  model: opus</span></span>
<span class="line"><span>  prompt: &quot;You write a concise summary.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>parallel:</span></span>
<span class="line"><span>  findings = session: researcher</span></span>
<span class="line"><span>    prompt: &quot;Research {topic}.&quot;</span></span>
<span class="line"><span>  draft = session: writer</span></span>
<span class="line"><span>    prompt: &quot;Summarize {topic}.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>session &quot;Merge the findings + draft into a final answer.&quot;</span></span>
<span class="line"><span>context: { findings, draft }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h2 id="文件位置" tabindex="-1"><a class="header-anchor" href="#文件位置">#</a> 文件位置</h2><p>OpenProse 将状态保存在工作空间的 <code>.prose/</code> 下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.prose/</span></span>
<span class="line"><span>├── .env</span></span>
<span class="line"><span>├── runs/</span></span>
<span class="line"><span>│   └── {YYYYMMDD}-{HHMMSS}-{random}/</span></span>
<span class="line"><span>│       ├── program.prose</span></span>
<span class="line"><span>│       ├── state.md</span></span>
<span class="line"><span>│       ├── bindings/</span></span>
<span class="line"><span>│       └── agents/</span></span>
<span class="line"><span>└── agents/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>用户级持久智能体位于：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.prose/agents/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="状态模式" tabindex="-1"><a class="header-anchor" href="#状态模式">#</a> 状态模式</h2><p>OpenProse 支持多种状态后端：</p><ul><li><strong>filesystem</strong>（默认）：<code>.prose/runs/...</code></li><li><strong>in-context</strong>：瞬态，用于小程序</li><li><strong>sqlite</strong>（实验性）：需要 <code>sqlite3</code> 二进制文件</li><li><strong>postgres</strong>（实验性）：需要 <code>psql</code> 和连接字符串</li></ul><p>说明：</p><ul><li>sqlite/postgres 是选择加入的，且处于实验阶段。</li><li>postgres 凭证会流入子智能体日志；请使用专用的、最小权限的数据库。</li></ul><h2 id="远程程序" tabindex="-1"><a class="header-anchor" href="#远程程序">#</a> 远程程序</h2><p><code>/prose run &lt;handle/slug&gt;</code> 解析为 <code>https://p.prose.md/&lt;handle&gt;/&lt;slug&gt;</code>。 直接 URL 按原样获取。这使用 <code>web_fetch</code> 工具（或用于 POST 的 <code>exec</code>）。</p><h2 id="opensoul-运行时映射" tabindex="-1"><a class="header-anchor" href="#opensoul-运行时映射">#</a> OpenSoul 运行时映射</h2><p>OpenProse 程序映射到 OpenSoul 原语：</p><table tabindex="0"><thead><tr><th>OpenProse 概念</th><th>OpenSoul 工具</th></tr></thead><tbody><tr><td>生成会话 / Task 工具</td><td><code>sessions_spawn</code></td></tr><tr><td>文件读/写</td><td><code>read</code> / <code>write</code></td></tr><tr><td>Web 获取</td><td><code>web_fetch</code></td></tr></tbody></table><p>如果你的工具白名单阻止这些工具，OpenProse 程序将失败。参见 <a href="/docs/tools/skills-config">Skills 配置</a>。</p><h2 id="安全-批准" tabindex="-1"><a class="header-anchor" href="#安全-批准">#</a> 安全 + 批准</h2><p>将 <code>.prose</code> 文件视为代码。运行前请审查。使用 OpenSoul 工具白名单和批准门控来控制副作用。</p><p>对于确定性的、批准门控的工作流，可与 <a href="/docs/tools/lobster">Lobster</a> 比较。</p>`,36)])])}const b=n(l,[["render",r]]);export{u as __pageData,b as default};
